from flask import Flask, request, g
import sqlite3

@app.route("/api/user")
def get_user():
    username = request.args.get("username")
    # SAFE: the ? placeholder is filled by the database driver
    cursor = g.db.execute(
        "SELECT * FROM users WHERE username = ?",
        (username,)
    )
    return cursor.fetchone()

# With SQLAlchemy ORM -- also safe because the ORM parameterizes for you
@app.route("/api/user")
def get_user_orm():
    username = request.args.get("username")
    user = User.query.filter_by(username=username).first()
    if not user:
        abort(404)
    return user.to_dict()
